// This function creates a dynamic context using the Manuscript file and summaries
function createDynamicContext(items) {
  try {
    console.log("Starting dynamic context creation...");

    // IMPORTANT: Get the current chapter from Initialize Chapter Loop3
    // This is the most accurate source of chapter numbers
    let currentChapter = 0;
    let nextChapter = 0;

    try {
      const initLoopData = $('Initialize Chapter Loop3').last().json;
      console.log("Initialize Chapter Loop3 data found:", JSON.stringify(initLoopData).substring(0, 200) + "...");

      currentChapter = initLoopData.currentChapter || 0;
      nextChapter = initLoopData.nextChapter || 0;

      console.log(`Got from Initialize Chapter Loop3: current=${currentChapter}, next=${nextChapter}`);

      // If we couldn't get the chapter numbers, fall back to items input
      if (currentChapter === 0 || nextChapter === 0) {
        console.log("Could not get valid chapter numbers from If3, using input data");
        currentChapter = items[0].json.currentChapter || 0;
        nextChapter = items[0].json.nextChapter || 0;
      }

      // If we still don't have valid numbers, try one last approach
      if (currentChapter === 0 || nextChapter === 0) {
        console.log("Still no valid chapter numbers, searching manuscript for highest chapter");
        // We'll scan the manuscript to find the highest chapter number
        const manuscriptScan = $('Get Manuscript3').last().json.content || "";

        // Look for the highest chapter with an END marker
        const endChapterRegex = /\[END CHAPTER (\d+)\]/g;
        let match;
        let highestChapter = 0;

        while ((match = endChapterRegex.exec(manuscriptScan)) !== null) {
          const chapterNum = parseInt(match[1], 10);
          if (chapterNum > highestChapter) {
            highestChapter = chapterNum;
          }
        }

        if (highestChapter > 0) {
          currentChapter = highestChapter;
          nextChapter = highestChapter + 1;
          console.log(`Found highest completed chapter in manuscript: ${currentChapter}`);
        } else {
          // Ultimate fallback
          console.log("No chapters found in manuscript, using defaults");
          currentChapter = 8;  // Default to Chapter 8
          nextChapter = 9;     // Default to Chapter 9
        }
      }
    } catch (error) {
      console.log("Error getting chapter numbers:", error.message);
      // Use fallback values
      currentChapter = 8;  // Default to Chapter 8
      nextChapter = 9;     // Default to Chapter 9
    }

    console.log(`Using chapter numbers: current=${currentChapter}, next=${nextChapter}`);

    // Get summaries document content
    let summaries = "";
    try {
      summaries = $('Get Summaries6').last().json.content || "No summaries available";
      console.log(`Retrieved summaries (${summaries.length} characters)`);
    } catch (error) {
      console.log(`Error getting summaries: ${error.message}`);
      summaries = "Error retrieving summaries.";
    }

    // Get the manuscript content
    let manuscriptContent = "";
    try {
      manuscriptContent = $('Get Manuscript3').last().json.content || "";
      console.log(`Retrieved manuscript (${manuscriptContent.length} characters)`);
    } catch (error) {
      console.log(`Error getting manuscript: ${error.message}`);
    }

    // Determine which previous chapters to include (most recent chapters)
    const chaptersToInclude = 4;
    const startChapter = Math.max(1, currentChapter - chaptersToInclude + 1);
    const endChapter = currentChapter;

    console.log(`Including chapters ${startChapter} through ${endChapter}`);

    // Explicitly extract each chapter by searching for BEGIN/END markers
    const recentChaptersText = [];

    for (let chNum = startChapter; chNum <= endChapter; chNum++) {
      console.log(`Looking for Chapter ${chNum}`);

      const beginMarker = `[BEGIN CHAPTER ${chNum}]`;
      const endMarker = `[END CHAPTER ${chNum}]`;

      const beginIndex = manuscriptContent.indexOf(beginMarker);

      if (beginIndex >= 0) {
        const endIndex = manuscriptContent.indexOf(endMarker, beginIndex);

        if (endIndex >= 0) {
          // Found both markers - extract the complete chapter
          const chapterContent = manuscriptContent.substring(beginIndex, endIndex + endMarker.length);
          console.log(`Found Chapter ${chNum} with BEGIN/END markers (${chapterContent.length} chars)`);
          recentChaptersText.push(chapterContent);
        } else {
          // Only found begin marker - look for next chapter's begin
          console.log(`No END marker for Chapter ${chNum}, looking for next chapter start`);
          let nextBeginIndex = manuscriptContent.length;

          for (let nextChap = chNum + 1; nextChap <= endChapter + 2; nextChap++) {
            const nextBeginMarker = `[BEGIN CHAPTER ${nextChap}]`;
            const tempIndex = manuscriptContent.indexOf(nextBeginMarker);

            if (tempIndex > beginIndex && tempIndex < nextBeginIndex) {
              nextBeginIndex = tempIndex;
              console.log(`Found next chapter ${nextChap} start at ${nextBeginIndex}`);
              break;
            }
          }

          if (nextBeginIndex < manuscriptContent.length) {
            const chapterContent = manuscriptContent.substring(beginIndex, nextBeginIndex);
            console.log(`Found incomplete Chapter ${chNum} using next chapter marker (${chapterContent.length} chars)`);
            recentChaptersText.push(chapterContent + `[END CHAPTER ${chNum}]`);
          }
        }
      } else {
        console.log(`Could not find BEGIN marker for Chapter ${chNum}`);
      }
    }

    console.log(`Found ${recentChaptersText.length} chapters to include`);

    // Create the dynamic context with literal text (no JSON parsing)
    const dynamicContext = `
CHAPTER SUMMARIES:
${summaries}

RECENT CHAPTERS:
${recentChaptersText.join('\n\n')}

NEXT CHAPTER TO WRITE: Chapter ${nextChapter}
`;

    console.log(`Created dynamic context (${dynamicContext.length} characters)`);

    // Add the dynamic context to the output
    items[0].json.dynamicContext = dynamicContext;

    return items;
  } catch (error) {
    console.log('Critical Error in Create Dynamic Context:');
    console.log(error.message);
    console.log(error.stack);

    // Simple fallback
    return [{
      json: {
        error: `Error in dynamic context creation: ${error.message}`,
        dynamicContext: `CHAPTER SUMMARIES:\n${items[0].json.content ? "Summaries available but error occurred" : "No summaries available"}\n\nRECENT CHAPTERS:\nError loading chapters\n\nNEXT CHAPTER TO WRITE: Chapter ${items[0].json.nextChapter || 9}`
      }
    }];
  }
}

// Execute the function
return createDynamicContext($input.all());

