function initializeChapterLoop() {
  console.log("Initializing chapter loop");

  // Detect current chapter from manuscript
  let currentChapter = 0; // Default fallback
  let nextChapter = 1;

  try {
    // Get the manuscript content
    const manuscriptDocument = $('Get Manuscript5').last().json.content || "";
    console.log(`Manuscript content length for initialization: ${manuscriptDocument.length}`);

    // Find all chapter markers
    const chapterRegex = /\[BEGIN CHAPTER (\d+)\]/g;
    let match;
    let highestChapter = 0;
    let foundChapters = [];

    while ((match = chapterRegex.exec(manuscriptDocument)) !== null) {
      const chapterNum = parseInt(match[1], 10);
      foundChapters.push(chapterNum);
      if (chapterNum > highestChapter) {
        highestChapter = chapterNum;
      }
    }

    console.log(`Found chapters: ${foundChapters.join(', ')}`);
    console.log(`Highest chapter found in manuscript: ${highestChapter}`);

    // If we found chapters, use the highest as current chapter
    if (highestChapter > 0) {
      currentChapter = highestChapter;
      nextChapter = highestChapter + 1;
    }
  } catch (error) {
    console.log("Error detecting chapters during initialization:", error.message);
  }

  console.log(`Using chapter numbers: current=${currentChapter}, next=${nextChapter}`);

  return [{
    json: {
      currentChapter: currentChapter,
      nextChapter: nextChapter,
      chapterNumber: nextChapter,
      totalChaptersToCreate: parseInt($('On form submission').last().json['Total Chapters']),
      workflowStartTime: new Date().toISOString()
    }
  }];
}

// Execute the function
return initializeChapterLoop();

// Function to extract a single chapter from the outline document based on chapter number
function extractSingleChapter(items) {
  try {
    // DIRECT APPROACH: Check manuscript for highest chapter
    let manuscriptDocument = "";

    // Only try to get manuscript from 'Get Manuscript3' node
    try {
      console.log("Getting manuscript from 'Get Manuscript1' node");
      manuscriptDocument = $('Get Manuscript1').last().json.content || "";
      console.log(`Manuscript content length: ${manuscriptDocument.length}`);
    } catch (nodeError) {
      console.log("Error getting manuscript from 'Get Manuscript1':", nodeError.message);
      return [{
        json: {
          error: "Could not get manuscript from 'Get Manuscript1'. Make sure this node is connected properly and executed.",
          errorDetails: nodeError.message
        }
      }];
    }

    let highestExistingChapter = 0;
    let foundChapters = [];

    // Look for [BEGIN CHAPTER X] pattern in the manuscript
    const chapterRegex = /\[BEGIN CHAPTER (\d+)\]/g;
    let match;

    while ((match = chapterRegex.exec(manuscriptDocument)) !== null) {
      const chapterNum = parseInt(match[1], 10);
      foundChapters.push(chapterNum);
      if (chapterNum > highestExistingChapter) {
        highestExistingChapter = chapterNum;
      }
    }

    // The NEXT chapter to extract is highest + 1
    const nextChapter = highestExistingChapter + 1;
    console.log(`Next chapter to extract: ${nextChapter} (after found highest: ${highestExistingChapter})`);

    // Get the outline document
    let outlineDocument;
    try {
      console.log("Getting outline from 'Get Outline' node");
      outlineDocument = $('Get Outline').last().json.content || "";
      console.log(`Outline document length: ${outlineDocument.length}`);
    } catch (nodeError) {
      console.log("Error getting outline document:", nodeError.message);
      return [{
        json: {
          error: "Could not get outline document. Make sure 'Get Outline' node is connected properly.",
          errorDetails: nodeError.message,
          currentChapter: highestExistingChapter,
          nextChapter: nextChapter,
          chapterNumber: nextChapter
        }
      }];
    }

    // Use nextChapter for all references
    const titlePattern = new RegExp(`CHAPTER\\s*${nextChapter}\\s*:\\s*([^\\n]+)`, 'i');
    const titleMatch = outlineDocument.match(titlePattern);

    if (!titleMatch) {
      console.log(`ERROR: Chapter ${nextChapter} not found in outline`);
      return [{
        json: {
          error: `Chapter ${nextChapter} not found in outline`,
          currentChapter: highestExistingChapter,
          nextChapter: nextChapter,
          chapterNumber: nextChapter,
          highestExistingChapter: highestExistingChapter,
          foundChapters: foundChapters
        }
      }];
    }

    const chapterTitle = titleMatch[1].trim().replace(/\*\*/g, '');
    console.log(`FOUND TITLE: Chapter ${nextChapter}: ${chapterTitle}`);

    // Find the chapter content using nextChapter consistently
    const startPattern = new RegExp(`CHAPTER\\s*${nextChapter}\\s*:`, 'i');
    const endPattern = new RegExp(`CHAPTER\\s*${nextChapter + 1}\\s*:`, 'i');

    // Find the start position
    const startMatch = outlineDocument.match(startPattern);
    if (!startMatch) {
      return [{
        json: {
          error: `Could not determine chapter start position`,
          currentChapter: highestExistingChapter,
          nextChapter: nextChapter,
          chapterNumber: nextChapter,
          chapterTitle: chapterTitle
        }
      }];
    }

    const startPos = startMatch.index;

    // Find the end position (next chapter or end of document)
    let endPos = outlineDocument.length;
    const endMatch = outlineDocument.match(endPattern);
    if (endMatch) {
      endPos = endMatch.index;
    }

    // Extract the full chapter content
    const chapterContent = outlineDocument.substring(startPos, endPos);

    // Extract each section with simple patterns
    const chapterDetails = {};
    const sections = [
      { name: "chapterGoal", label: "Chapter Goal" },
      { name: "keyPlotPoints", label: "Key Plot Points" },
      { name: "romComElements", label: "Rom-Com Elements" },
      { name: "characterDevelopment", label: "Character Development" },
      { name: "settingDetails", label: "Setting Details" },
      { name: "subplotProgression", label: "Subplot Progression" },
      { name: "chapterEnding", label: "Chapter Ending" }
    ];

    for (const section of sections) {
      const sectionPattern = new RegExp(`${section.label}\\s+([\\s\\S]*?)(?=##|$)`, 'i');
      const sectionMatch = chapterContent.match(sectionPattern);

      if (sectionMatch) {
        let content = sectionMatch[1].trim();
        // Clean up content
        content = content.replace(/- /g, "• ");
        content = content.replace(/\*\*/g, '');
        chapterDetails[section.name] = content;
      } else {
        chapterDetails[section.name] = "";
      }
    }

    // Check if this is the last chapter
    const hasNextChapter = endMatch !== null;

    // Format the chapter outline using nextChapter
    const chapterOutline = `Chapter ${nextChapter}: ${chapterTitle}
Chapter Goal
${chapterDetails.chapterGoal || ""}
Key Plot Points
${chapterDetails.keyPlotPoints || ""}
Rom-Com Elements
${chapterDetails.romComElements || ""}
Character Development
${chapterDetails.characterDevelopment || ""}
Setting Details
${chapterDetails.settingDetails || ""}
Subplot Progression
${chapterDetails.subplotProgression || ""}
Chapter Ending
${chapterDetails.chapterEnding || ""}
`;

    // Get Google Drive folder ID if available
    let folderId = "";
    try {
      folderId = $('Google Drive').first().json.id || "";
    } catch (driveError) {
      console.log("Could not get Google Drive folder ID:", driveError.message);
    }

    // Return the extracted chapter details with consistent chapter numbers
    return [{
      json: {
        currentChapter: highestExistingChapter, // The current chapter in manuscript
        nextChapter: nextChapter, // The chapter after this one
        chapterNumber: nextChapter, // The chapter we're extracting NOW
        chapterTitle: chapterTitle,
        documentTitle: `Chapter ${nextChapter} - ${chapterTitle}`,
        chapterOutline: chapterOutline,
        chapterDetails: chapterDetails,
        folderId: folderId,
        isLastChapter: !hasNextChapter,
        highestExistingChapter: highestExistingChapter,
        foundChapters: foundChapters
      }
    }];
  } catch (error) {
    console.log("Error:", error.message);
    console.log(error.stack); // Log the stack trace for more detailed debugging
    return [{
      json: {
        error: error.message,
        stack: error.stack
      }
    }];
  }
}

// Execute the function
return extractSingleChapter($input.all());

