// This function routes chapters to the appropriate processing loop
function routeChapterProcessing(items) {
  try {
    // Get system data from the previous node
    const systemData = items[0].json || {};

    // Get the Summaries document ID and content
    let summariesDocId = "";
    let summariesContent = "";

    try {
      // Get Summaries ID from the docMap in Set IDs
      summariesDocId = $('Set IDs').last().json.docMap.Summaries || "";
      console.log(`Summaries document ID: ${summariesDocId}`);

      // Try to get the content from Get Summaries2 if it's been executed
      try {
        summariesContent = $('Get Summaries2').last().json.content || "";
        console.log(`Retrieved summaries content length: ${summariesContent.length} characters`);
      } catch (contentError) {
        console.log("Could not access summaries content: ", contentError.message);
      }
    } catch (docError) {
      console.log("Could not access docMap: ", docError.message);
    }

    // Get the manuscript content to check chapter count
    let manuscriptContent = "";
    try {
      manuscriptContent = $('Get Manuscript').last().json.content || "";
      console.log(`Retrieved manuscript content length: ${manuscriptContent.length} characters`);
    } catch (manuscriptError) {
      console.log("Could not access manuscript content: ", manuscriptError.message);
    }

    // Use regex to find all [BEGIN CHAPTER X] instances in manuscript
    const chapterRegex = /\[BEGIN CHAPTER (\d+)\]/g;
    let match;
    let highestChapter = 0;
    let foundChapters = [];

    while ((match = chapterRegex.exec(manuscriptContent)) !== null) {
      const chapterNum = parseInt(match[1], 10);
      foundChapters.push(chapterNum);
      if (chapterNum > highestChapter) {
        highestChapter = chapterNum;
      }
    }

    console.log(`Found ${foundChapters.length} chapters in manuscript, highest chapter: ${highestChapter}`);

    // Check for summaries using EXACT format: [CHAPTER X SUMMARY]
    // IMPORTANT: Use escaped brackets in regex since these are literal characters
    const summaryRegex = /\[CHAPTER (\d+) SUMMARY\]/g;
    const existingSummaries = [];

    // Find all summaries
    while ((match = summaryRegex.exec(summariesContent)) !== null) {
      const summaryNum = parseInt(match[1], 10);
      if (!isNaN(summaryNum) && !existingSummaries.includes(summaryNum)) {
        existingSummaries.push(summaryNum);
      }
    }

    // Sort for cleaner logging
    existingSummaries.sort((a, b) => a - b);
    console.log(`Found ${existingSummaries.length} existing chapter summaries: ${existingSummaries.join(', ')}`);

    // Determine if we need to create summaries
    const missingChapters = foundChapters.filter(ch => !existingSummaries.includes(ch));
    const needToCreateSummaries = missingChapters.length > 0;

    // Determine routing flags based on summaries and chapter count
    let useAdvancedLoop = false;
    let useBasicLoop = false;
    let createSummaries = false;
    let routingPath = "";

    if (needToCreateSummaries) {
      // Missing summaries for some chapters, create them first
      createSummaries = true;
      routingPath = "createSummaries";
      console.log(`Missing summaries detected for chapters: ${missingChapters.join(', ')}`);
    } else {
      // All chapters have summaries, route based on chapter count
      if (highestChapter >= 4) {
        useAdvancedLoop = true;
        routingPath = "advanced";
        console.log(`All summaries found, routing to advanced loop (chapter ${highestChapter} >= 4)`);
      } else {
        useBasicLoop = true;
        routingPath = "basic";
        console.log(`All summaries found, routing to basic loop (chapter ${highestChapter} < 4)`);
      }
    }

    // FORCE ADVANCED LOOP IF 6 CHAPTERS
    // This is a temporary workaround until we figure out the exact issue
    if (foundChapters.length >= 6) {
      useAdvancedLoop = true;
      useBasicLoop = false;
      createSummaries = false;
      routingPath = "advanced";
      console.log("OVERRIDE: Forcing advanced loop due to 6+ chapters being found");
    }

    console.log(`Routing decision: advanced=${useAdvancedLoop}, basic=${useBasicLoop}, createSummaries=${createSummaries}`);

    return [{
      json: {
        currentChapter: highestChapter,
        nextChapter: highestChapter + 1,
        useAdvancedLoop: useAdvancedLoop,
        useBasicLoop: useBasicLoop,
        createSummaries: createSummaries,
        foundChapters: foundChapters,
        existingSummaries: existingSummaries,
        needToCreateSummaries: needToCreateSummaries,
        routingPath: routingPath,
        summariesDocId: summariesDocId,
        // Include original system data to preserve it
        ...systemData
      }
    }];
  } catch (error) {
    console.log(`Error in routing function: ${error.message}`);
    return [{
      json: {
        error: error.message,
        useAdvancedLoop: false,
        useBasicLoop: true,
        createSummaries: false
      }
    }];
  }
}

// Execute the function
return routeChapterProcessing($input.all());

